        --f-spinner-height: 50px;
        --f-spinner-border-radius: 50%;
        --f-spinner-border-width: 4px
    }

    @keyframes f-spinner {
        to {
            rotate: 360deg
        }
    }

    .f-panzoom:before,.f-panzoom:after,.f-zoomable:before,.f-zoomable:after {
        display: block;
        content: ""
    }

    .f-panzoom:not(.has-controls):before,.f-zoomable:not(.has-controls):before {
        margin-bottom: auto
    }

    .f-panzoom:after,.f-zoomable:after {
        margin-top: auto
    }

    @keyframes f-fadeIn {
        0% {
            opacity: 0
        }

        to {
            opacity: 1
        }
    }

    @keyframes f-fadeOut {
        to {
            opacity: 0
        }
    }

    @keyframes f-crossfadeIn {
        0% {
            opacity: 0
        }

        to {
            opacity: 1
        }
    }

    @keyframes f-crossfadeOut {
        to {
            opacity: 0
        }
    }

    @keyframes f-slideInPrevX {
        0% {
            transform: translate(calc(100% + var(--f-carousel-gap,0)))
        }

        to {
            transform: translateZ(0)
        }
    }

    @keyframes f-slideInNextX {
        0% {
            transform: translate(calc(-100% - var(--f-carousel-gap,0)))
        }

        to {
            transform: translateZ(0)
        }
    }

    @keyframes f-slideOutNextX {
        to {
            transform: translate(calc(-100% - var(--f-carousel-gap,0)))
        }
    }

    @keyframes f-slideOutPrevX {
        to {
            transform: translate(calc(100% + var(--f-carousel-gap,0)))
        }
    }

    @keyframes f-slideInPrevY {
        0% {
            transform: translateY(calc(100% + var(--f-carousel-gap,0)))
        }

        to {
            transform: translateZ(0)
        }
    }

    @keyframes f-slideInNextY {
        0% {
            transform: translateY(calc(-100% - var(--f-carousel-gap,0)))
        }

        to {
            transform: translateZ(0)
        }
    }

    @keyframes f-slideOutNextY {
        to {
            transform: translateY(calc(-100% - var(--f-carousel-gap,0)))
        }
    }

    @keyframes f-slideOutPrevY {
        to {
            transform: translateY(calc(100% + var(--f-carousel-gap,0)))
        }
    }

    @keyframes f-zoomInUp {
        0% {
            transform: scale(var(--f-zoomInUp-scale,.975)) translate3d(var(--f-zoomInUp-x,0),var(--f-zoomInUp-y,16px),0);
            opacity: var(--f-zoomInUp-opacity,0)
        }

        to {
            transform: scale(1) translateZ(0);
            opacity: 1
        }
    }

    @keyframes f-zoomOutDown {
        to {
            transform: scale(var(--f-zoomOutDown-scale,.975)) translate3d(var(--f-zoomOutDown-x,0),var(--f-zoomOutDown-y,16px),0);
            opacity: 0
        }
    }

    @keyframes f-throwOutUp {
        to {
            transform: translate3d(0,calc(var(--f-throwOutUp-y,150px)*-1),0);
            opacity: 0
        }
    }

    @keyframes f-throwOutDown {
        to {
            transform: translate3d(0,var(--f-throwOutDown-y,150px),0);
            opacity: 0
        }
    }

    .f-carousel__toolbar .f-button:focus-visible {
        position: relative;
        z-index: 1
    }

    .home5 {
        --f-thumbs-gap: 8px;
        --f-thumbs-margin: 0;
        --f-thumbs-padding-x: 8px;
        --f-thumbs-padding-y: 8px;
        --f-thumbs-bg: transparent;
        --f-thumbs-transition: max-height .3s ease,max-width .3s ease,padding .3s ease;
        --f-thumbs-z-index: 1;
        --f-thumbs-viewport-padding-x: 0px;
        --f-thumbs-viewport-padding-y: 0px;
        --f-thumb-width: 94px;
        --f-thumb-height: 76px;
        --f-thumb-clip-width: 46px;
        --f-thumb-extra-gap: 16px;
        --f-thumb-opacity: 1;
        --f-thumb-transition: opacity .3s ease,transform .15s ease;
        --f-thumb-border: 0;
        --f-thumb-border-radius: 4px;
        --f-thumb-shadow: none;
        --f-thumb-bg: linear-gradient(rgba(0,0,0,.1),rgba(0,0,0,.05));
        --f-thumb-focus-shadow: inset 0 0 0 .8px #222,inset 0 0 0 2.25px #fff;
        --f-thumb-selected-shadow: inset 0 0 0 .8px #222,inset 0 0 0 2.25px #fff;
        --f-thumb-border-transition: all .1s ease;
        --f-thumb-img-width: 100%;
        --f-thumb-img-height: 100%;
        --f-thumb-img-fit: cover;
        --f-thumb-img-position: 50% 20%
    }

    .f-thumbs__slide:hover .home5 button {
        opacity: var(--f-thumb-hover-opacity,1);
        transform: var(--f-thumb-hover-transform,none)
    }

    .f-thumbs__slide:hover button:after {
        border: var(--f-thumb-hover-border,none);
        box-shadow: var(--f-thumb-hover-shadow,var(--f-thumb-shadow))
    }

    .f-thumbs__slide button:after {
        content: "";
        position: absolute;
        inset: 0;
        z-index: 1;
        transition: var(--f-thumb-border-transition);
        border-radius: inherit;
        border: var(--f-thumb-border);
        box-shadow: var(--f-thumb-shadow)
    }

    .f-thumbs__slide button:focus-within {
        opacity: var(--f-thumb-focus-opacity,1);
        transform: var(--f-thumb-focus-transform,none)
    }

    .f-thumbs__slide button:focus-within:after {
        border: var(--f-thumb-focus-border,none);
        box-shadow: var(--f-thumb-focus-shadow,var(--f-thumb-shadow))
    }

    .f-thumbs__slide:active {
        opacity: var(--f-thumb-active-opacity,1);
        transform: var(--f-thumb-active-transform,none)
    }

    .f-thumbs__slide:active:after {
        border: var(--f-thumb-active-border,none);
        box-shadow: var(--f-thumb-active-shadow,var(--f-thumb-shadow))
    }

    .f-thumbs__slide.is-selected button:after {
        border: var(--f-thumb-selected-border,none);
        box-shadow: var(--f-thumb-selected-shadow,var(--f-thumb-shadow))
    }

    .f-thumbs.is-modern .f-thumbs__slide button:after {
        display: none
    }

    .f-thumbs.is-modern .f-thumbs__slide:focus:not(:focus-visible) {
        outline: 0
    }

    .f-thumbs.is-modern .f-thumbs__slide:focus-within:not(.is-selected) button:before {
        content: "";
        position: absolute;
        z-index: 1;
        top: 0;
        left: var(--clip-shift);
        bottom: 0;
        right: var(--clip-shift);
        transition: border var(--f-transition-duration) var(--f-transition-easing),box-shadow var(--f-transition-duration) var(--f-transition-easing);
        border-radius: inherit;
        border: var(--f-thumb-focus-border,none);
        box-shadow: var(--f-thumb-focus-shadow,none)
    }

    .home5 {
