    .home5 {
        --color-primary: #ff5626;
        --color-secondary: #ff7a23;
        --color-tertiary: #f44024;
        --background-page: #f5f7f9
    }

    .container-home5 {
        max-width: 1220px !important;
        padding: 0 10px;
        margin: 0 auto
    }

    .heading-primary {
        font-family: "Gilroy",sans-serif;
        font-size: 36px;
        font-weight: 700;
        line-height: 1.25;
        text-align: center;
        text-transform: uppercase
    }

    .button-primary {
        position: relative;
        font-size: 14px;
        font-weight: 700;
        line-height: 43px;
        text-transform: uppercase;
        text-align: center;
        letter-spacing: 1px;
        border-radius: 24px;
        color: #fff;
        padding: 0 40px;
        background: linear-gradient(90deg,#f3d278 0%,#f16744 100%);
        overflow: hidden
    }

    .button-primary::before {
        content: "";
        position: absolute;
        top: 2px;
        left: 2px;
        right: 2px;
        bottom: 2px;
        background: transparent;
        border: 1px solid #fff;
        border-radius: 24px;
        transition: all .150s
    }

    .button-primary:hover {
        color: #fff;
        background: #f16744
    }

    .button-primary:hover::before {
        top: -1px;
        left: -1px;
        right: -1px;
        bottom: -1px
    }

    .swiper-wrapper {
        height: auto
    }

    .section-audiogram .audiogram-line::before {
        content: "";
        flex: 1;
        background: var(--background-page)
    }

    .section-audiogram .audiogram-line::after {
        content: "";
        flex: 1;
        background: var(--background-page)
    }

    .section-deployment::after {
        position: absolute;
        width: 0;
        height: 0;
        overflow: hidden;
        z-index: -1;
        content: url(data:image/jpeg;base64,)url(data:image/jpeg;base64,)url(data:image/jpeg;base64,)url(data:image/jpeg;base64,)url(data:image/jpeg;base64,)
    }

    .section-featured .featured-slider::before {
        content: "";
        width: 60%;
        height: 100%;
        position: absolute;
        left: 0;
        background: var(--sf-img-10) no-repeat;
        background-size: cover;
        mask-image: linear-gradient(-90deg,#0000 15%,#000 50%);
        z-index: 9
    }

    .section-featured .featured-slider::after {
        content: "";
        width: 25%;
        height: 100%;
        position: absolute;
        right: 0;
        background: var(--sf-img-10) no-repeat;
        background-size: cover;
        mask-image: linear-gradient(90deg,#0000 10%,#000 95%);
        z-index: 9
    }

    .global-popup-modal__button.close:hover {
